#include <comp421/yalnix.h>
#include <comp421/filesystem.h>
#include <stdlib.h>
#include <string.h>
#include <stdio.h>

/* Message types for IPC */
#define MSG_OPEN        1
#define MSG_CLOSE       2
#define MSG_CREATE      3
#define MSG_READ        4
#define MSG_WRITE       5
#define MSG_SEEK        6
#define MSG_LINK        7
#define MSG_UNLINK      8
#define MSG_SYMLINK     9
#define MSG_READLINK    10
#define MSG_MKDIR       11
#define MSG_RMDIR       12
#define MSG_CHDIR       13
#define MSG_STAT        14
#define MSG_SYNC        15
#define MSG_SHUTDOWN    16

/* Message structure - exactly 32 bytes */
struct message {
    int type;
    int cwd_inum;
    int fd;
    int position;
    int size;
    void *pathname_ptr;
    int pathname_len;
    void *data_ptr;
    int data_size;
};

/* Reply message - exactly 32 bytes */
struct reply {
    int result;
    int inum;
    int reuse;
    int stat_type;
    int stat_size;
};

/* Cache entry for blocks */
struct block_cache_entry {
    int block_num;
    unsigned char data[BLOCKSIZE];
    int dirty;
    struct block_cache_entry *prev;
    struct block_cache_entry *next;
};

/* Cache entry for inodes */
struct inode_cache_entry {
    int inum;
    struct inode data;
    int dirty;
    struct inode_cache_entry *prev;
    struct inode_cache_entry *next;
};

/* Global state */
static struct inode root_inode;
static struct inode_cache_entry *inode_cache[INODE_CACHESIZE];
static struct block_cache_entry *block_cache[BLOCK_CACHESIZE];
static struct inode_cache_entry *inode_cache_head = NULL;
static struct inode_cache_entry *inode_cache_tail = NULL;
static struct block_cache_entry *block_cache_head = NULL;
static struct block_cache_entry *block_cache_tail = NULL;
static struct fs_header fs_header;
static int *free_inodes;
static int free_inodes_count = 0;
static int *free_blocks;
static int free_blocks_count = 0;

int main(int argc, char **argv)
{
    int sender_pid;
    struct message msg;
    struct reply reply;
    int child_pid;

    /* Initialize free lists */
    free_inodes = (int *)malloc(sizeof(int) * 10000);
    free_blocks = (int *)malloc(sizeof(int) * 10000);

    /* Register as file server */
    Register(FILE_SERVER);

    /* Fork and exec first test program if provided */
    if (argc > 1) {
        child_pid = Fork();
        if (child_pid == 0) {
            Exec(argv[1], argv + 1);
        }
    }

    /* Main server loop */
    while (1) {
        sender_pid = Receive(&msg);

        if (sender_pid == 0) {
            /* Deadlock break */
            break;
        }

        if (sender_pid == ERROR) {
            continue;
        }

        /* Initialize reply */
        memset(&reply, 0, sizeof(reply));
        reply.result = ERROR;

        /* Dispatch based on message type */
        switch (msg.type) {
            case MSG_OPEN:
                break;
            case MSG_CLOSE:
                break;
            case MSG_CREATE:
                break;
            case MSG_READ:
                break;
            case MSG_WRITE:
                break;
            case MSG_SEEK:
                break;
            case MSG_MKDIR:
                break;
            case MSG_RMDIR:
                break;
            case MSG_CHDIR:
                break;
            case MSG_STAT:
                break;
            case MSG_SYNC:
                reply.result = 0;
                break;
            case MSG_SHUTDOWN:
                reply.result = 0;
                Reply(&reply, sender_pid);
                Sync();
                Exit(0);
                break;
            default:
                break;
        }

        Reply(&reply, sender_pid);
    }

    return 0;
}

