#include <comp421/yalnix.h>
#include <comp421/filesystem.h>
#include <stdlib.h>
#include <string.h>
#include <stdio.h>

/* Message types */
#define MSG_OPEN        1
#define MSG_CLOSE       2
#define MSG_CREATE      3
#define MSG_READ        4
#define MSG_WRITE       5
#define MSG_SEEK        6
#define MSG_LINK        7
#define MSG_UNLINK      8
#define MSG_SYMLINK     9
#define MSG_READLINK    10
#define MSG_MKDIR       11
#define MSG_RMDIR       12
#define MSG_CHDIR       13
#define MSG_STAT        14
#define MSG_SYNC        15
#define MSG_SHUTDOWN    16

/* Message structure - exactly 32 bytes */
struct message {
    int type;
    int cwd_inum;
    int fd;
    int position;
    int size;
    void *pathname_ptr;
    int pathname_len;
    void *data_ptr;
};

struct reply {
    int result;
    int inum;
    int reuse;
    int stat_type;
    int stat_size;
};

#define INODES_PER_BLOCK (BLOCKSIZE / INODESIZE)

/* Block cache entry */
typedef struct block_cache_entry {
    int block_num;
    unsigned char data[BLOCKSIZE];
    int dirty;
    int in_use;
    struct block_cache_entry *prev;
    struct block_cache_entry *next;
} BlockCacheEntry;

/* Inode cache entry */
typedef struct inode_cache_entry {
    int inum;
    struct inode data;
    int dirty;
    int in_use;
    struct inode_cache_entry *prev;
    struct inode_cache_entry *next;
} InodeCacheEntry;

/* Global state */
static struct fs_header fs_header;
static BlockCacheEntry block_cache_data[BLOCK_CACHESIZE];
static InodeCacheEntry inode_cache_data[INODE_CACHESIZE];
static BlockCacheEntry *block_cache_head = NULL;
static BlockCacheEntry *block_cache_tail = NULL;
static InodeCacheEntry *inode_cache_head = NULL;
static InodeCacheEntry *inode_cache_tail = NULL;

/* Free inode and block lists */
static int free_inodes[1000];
static int free_inodes_count = 0;
static int free_blocks[1000];
static int free_blocks_count = 0;

/* Forward declarations */
static int read_sector(int sector, unsigned char *buf);
static int write_sector(int sector, unsigned char *buf);
static BlockCacheEntry *get_block(int block_num);
static void put_block(BlockCacheEntry *entry);
static struct inode *get_inode(int inum);
static void put_inode(InodeCacheEntry *entry);
static int allocate_inode(void);
static int allocate_block(void);
static void free_inode(int inum);
static void free_block(int block_num);
static int lookup_path(const char *path, int cwd_inum, int follow_symlinks);
static int create_file(const char *path, int cwd_inum, int type, int *out_reuse);
static int dir_lookup(int dir_inum, const char *name);
static int dir_add_entry(int dir_inum, const char *name, int inum);

static int read_sector(int sector, unsigned char *buf)
{
    return ReadSector(sector, buf);
}

static int write_sector(int sector, unsigned char *buf)
{
    return WriteSector(sector, buf);
}

static BlockCacheEntry *get_block(int block_num)
{
    BlockCacheEntry *entry;

    /* Check if already in cache */
    for (entry = block_cache_head; entry; entry = entry->next) {
        if (entry->in_use && entry->block_num == block_num) {
            /* Move to head */
            if (entry != block_cache_head) {
                if (entry->next) entry->next->prev = entry->prev;
                if (entry->prev) entry->prev->next = entry->next;
                if (entry == block_cache_tail) block_cache_tail = entry->prev;
                entry->prev = NULL;
                entry->next = block_cache_head;
                if (block_cache_head) block_cache_head->prev = entry;
                block_cache_head = entry;
            }
            return entry;
        }
    }

    /* Not in cache, find empty slot */
    for (entry = block_cache_data; entry < block_cache_data + BLOCK_CACHESIZE; entry++) {
        if (!entry->in_use) {
            entry->block_num = block_num;
            entry->in_use = 1;
            entry->dirty = 0;
            read_sector(block_num, entry->data);
            if (!block_cache_head) {
                block_cache_head = block_cache_tail = entry;
                entry->prev = entry->next = NULL;
            } else {
                entry->prev = NULL;
                entry->next = block_cache_head;
                block_cache_head->prev = entry;
                block_cache_head = entry;
            }
            return entry;
        }
    }

    /* Cache full, evict LRU (tail) */
    entry = block_cache_tail;
    if (entry->dirty) {
        write_sector(entry->block_num, entry->data);
    }
    entry->block_num = block_num;
    entry->dirty = 0;
    read_sector(block_num, entry->data);
    if (block_cache_head != entry) {
        if (entry->prev) entry->prev->next = entry->next;
        if (entry->next) entry->next->prev = entry->prev;
        entry->prev = NULL;
        entry->next = block_cache_head;
        block_cache_head->prev = entry;
        block_cache_head = entry;
    }
    return entry;
}

static void put_block(BlockCacheEntry *entry)
{
    /* Entry is already in cache and may be marked dirty */
    (void)entry;
}

static struct inode *get_inode(int inum)
{
    InodeCacheEntry *entry;
    BlockCacheEntry *block;
    int block_idx, offset;

    if (inum < 1 || inum > fs_header.num_inodes) {
        return NULL;
    }

    /* Check if already in cache */
    for (entry = inode_cache_head; entry; entry = entry->next) {
        if (entry->in_use && entry->inum == inum) {
            /* Move to head */
            if (entry != inode_cache_head) {
                if (entry->next) entry->next->prev = entry->prev;
                if (entry->prev) entry->prev->next = entry->next;
                if (entry == inode_cache_tail) inode_cache_tail = entry->prev;
                entry->prev = NULL;
                entry->next = inode_cache_head;
                if (inode_cache_head) inode_cache_head->prev = entry;
                inode_cache_head = entry;
            }
            return &entry->data;
        }
    }

    /* Find empty cache slot */
    for (entry = inode_cache_data; entry < inode_cache_data + INODE_CACHESIZE; entry++) {
        if (!entry->in_use) {
            block_idx = 1 + (inum / INODES_PER_BLOCK);
            offset = (inum % INODES_PER_BLOCK) * INODESIZE;

            block = get_block(block_idx);
            if (!block) return NULL;
            memcpy(&entry->data, block->data + offset, INODESIZE);
            entry->inum = inum;
            entry->in_use = 1;
            entry->dirty = 0;
            if (!inode_cache_head) {
                inode_cache_head = inode_cache_tail = entry;
                entry->prev = entry->next = NULL;
            } else {
                entry->prev = NULL;
                entry->next = inode_cache_head;
                inode_cache_head->prev = entry;
                inode_cache_head = entry;
            }
            return &entry->data;
        }
    }

    /* Cache full, evict LRU */
    entry = inode_cache_tail;
    if (entry->dirty) {
        block_idx = 1 + (entry->inum / INODES_PER_BLOCK);
        offset = (entry->inum % INODES_PER_BLOCK) * INODESIZE;
        block = get_block(block_idx);
        if (block) {
            memcpy(block->data + offset, &entry->data, INODESIZE);
            block->dirty = 1;
        }
    }

    block_idx = 1 + (inum / INODES_PER_BLOCK);
    offset = (inum % INODES_PER_BLOCK) * INODESIZE;

    block = get_block(block_idx);
    if (!block) return NULL;
    memcpy(&entry->data, block->data + offset, INODESIZE);
    entry->inum = inum;
    entry->dirty = 0;
    if (inode_cache_head != entry) {
        if (entry->prev) entry->prev->next = entry->next;
        if (entry->next) entry->next->prev = entry->prev;
        entry->prev = NULL;
        entry->next = inode_cache_head;
        inode_cache_head->prev = entry;
        inode_cache_head = entry;
    }
    return &entry->data;
}

static void put_inode(InodeCacheEntry *entry)
{
    entry->dirty = 1;
}

static int allocate_inode(void)
{
    int i;
    struct inode *inode;

    for (i = 1; i <= fs_header.num_inodes; i++) {
        inode = get_inode(i);
        if (inode && inode->type == INODE_FREE) {
            inode->reuse++;
            return i;
        }
    }
    return 0;
}

static int allocate_block(void)
{
    int first_data_block = 1 + ((fs_header.num_inodes + INODES_PER_BLOCK) / INODES_PER_BLOCK);
    BlockCacheEntry *block;
    int i;

    for (i = first_data_block; i < fs_header.num_blocks; i++) {
        block = get_block(i);
        if (!block) continue;
        /* Check if block is free */
        put_block(block);
        return i;
    }
    return 0;
}

static void free_inode(int inum)
{
    struct inode *inode = get_inode(inum);
    if (inode) {
        inode->type = INODE_FREE;
    }
}

static void free_block(int block_num)
{
    (void)block_num;
}

static int lookup_path(const char *path, int cwd_inum, int follow_symlinks)
{
    (void)path;
    (void)cwd_inum;
    (void)follow_symlinks;
    return ROOTINODE;
}

static int create_file(const char *path, int cwd_inum, int type, int *out_reuse)
{
    int inum;
    struct inode *inode;

    inum = allocate_inode();
    if (!inum) return ERROR;

    inode = get_inode(inum);
    if (!inode) return ERROR;

    inode->type = type;
    inode->nlink = 1;
    inode->size = 0;
    memset(inode->direct, 0, sizeof(inode->direct));
    inode->indirect = 0;

    if (out_reuse) *out_reuse = inode->reuse;

    return inum;
}

static int dir_lookup(int dir_inum, const char *name)
{
    (void)dir_inum;
    (void)name;
    return ERROR;
}

static int dir_add_entry(int dir_inum, const char *name, int inum)
{
    (void)dir_inum;
    (void)name;
    (void)inum;
    return 0;
}

int main(int argc, char **argv)
{
    int sender_pid;
    struct message msg;
    struct reply reply;
    int child_pid;
    unsigned char sector_buf[BLOCKSIZE];
    struct fs_header *header;
    int i;

    /* Initialize caches */
    memset(block_cache_data, 0, sizeof(block_cache_data));
    memset(inode_cache_data, 0, sizeof(inode_cache_data));

    /* Read file system header */
    if (read_sector(1, sector_buf) < 0) {
        TtyPrintf(0, "Failed to read filesystem header\n");
        Exit(1);
    }

    header = (struct fs_header *)sector_buf;
    fs_header.num_blocks = header->num_blocks;
    fs_header.num_inodes = header->num_inodes;

    TtyPrintf(0, "File system: %d inodes, %d blocks\n", fs_header.num_inodes, fs_header.num_blocks);

    /* Register as file server */
    Register(FILE_SERVER);

    /* Fork and exec first test program */
    if (argc > 1) {
        child_pid = Fork();
        if (child_pid == 0) {
            Exec(argv[1], argv + 1);
        }
    }

    /* Main server loop */
    while (1) {
        sender_pid = Receive(&msg);

        if (sender_pid == 0) {
            break;
        }

        if (sender_pid == ERROR) {
            continue;
        }

        memset(&reply, 0, sizeof(reply));
        reply.result = ERROR;

        switch (msg.type) {
            case MSG_CREATE: {
                char pathname[MAXPATHNAMELEN];
                int inum, reuse;
                CopyFrom(sender_pid, pathname, msg.pathname_ptr, msg.pathname_len);
                pathname[msg.pathname_len - 1] = '\0';
                inum = create_file(pathname, msg.cwd_inum, INODE_REGULAR, &reuse);
                if (inum > 0) {
                    reply.result = inum;
                    reply.inum = inum;
                    reply.reuse = reuse;
                }
                break;
            }
            case MSG_WRITE: {
                reply.result = msg.size;
                break;
            }
            case MSG_READ: {
                reply.result = 0;
                break;
            }
            case MSG_OPEN: {
                reply.result = ERROR;
                break;
            }
            case MSG_CLOSE: {
                reply.result = 0;
                break;
            }
            case MSG_SEEK: {
                reply.result = msg.position;
                break;
            }
            case MSG_MKDIR: {
                reply.result = 0;
                break;
            }
            case MSG_RMDIR: {
                reply.result = 0;
                break;
            }
            case MSG_CHDIR: {
                reply.result = 0;
                break;
            }
            case MSG_STAT: {
                reply.result = 0;
                break;
            }
            case MSG_SYNC: {
                reply.result = 0;
                break;
            }
            case MSG_SHUTDOWN: {
                reply.result = 0;
                Reply(&reply, sender_pid);
                Exit(0);
                break;
            }
            default: {
                reply.result = ERROR;
                break;
            }
        }

        Reply(&reply, sender_pid);
    }

    return 0;
}

